// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.time.Duration;
import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.junit.jupiter.api.Test;

class RuleDescriptorContractTest {

	@Test
	void descriptorDeclaresEverySchedulerDependency() {
		RulePriority priority = new RulePriority(RulePhase.EXPENSIVE_LOGICAL, 73);
		RuleDescriptor descriptor = RuleDescriptor.builder("typed-contract", RuleKind.TRANSFORMATION)
				.rootOperators(RuleRootOperator.JOIN)
				.factsRead(RuleDescriptor.MemoFact.ASSURED_BINDINGS,
						RuleDescriptor.MemoFact.STATISTICS_EPOCH)
				.childPropertiesRead(RuleDescriptor.ChildProperty.ORDERING)
				.goalPropertiesRead(RuleDescriptor.GoalProperty.INVOCATION_CARDINALITY)
				.changesProduced(RuleDescriptor.ProducedChange.LOGICAL_EXPRESSION,
						RuleDescriptor.ProducedChange.MEMO_FACT)
				.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED)
				.priority(priority)
				.convergenceClass(RuleConvergenceClass.CANONICAL_REDUCTION)
				.build();

		assertEquals(Set.of(RuleRootOperator.JOIN), descriptor.rootOperators());
		assertEquals(Set.of(RuleDescriptor.MemoFact.ASSURED_BINDINGS,
				RuleDescriptor.MemoFact.STATISTICS_EPOCH), descriptor.factsRead());
		assertEquals(Set.of(RuleDescriptor.ChildProperty.ORDERING), descriptor.childPropertiesRead());
		assertEquals(Set.of(RuleDescriptor.GoalProperty.INVOCATION_CARDINALITY), descriptor.goalPropertiesRead());
		assertEquals(Set.of(RuleDescriptor.ProducedChange.LOGICAL_EXPRESSION,
				RuleDescriptor.ProducedChange.MEMO_FACT), descriptor.changesProduced());
		assertEquals(Set.of(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED,
				RuleWakeUpEvent.LOGICAL_FACT_CHANGED,
				RuleWakeUpEvent.STATISTICS_CHANGED,
				RuleWakeUpEvent.CHILD_EXPRESSION_CHANGED,
				RuleWakeUpEvent.CHILD_WINNER_CHANGED), descriptor.wakeUpEvents());
		assertEquals(priority, descriptor.priority());
		assertEquals(RuleConvergenceClass.CANONICAL_REDUCTION, descriptor.convergenceClass());
	}

	@Test
	void unauditedAndOpaqueGoalAwareRulesRetainInvocationCardinality() {
		Set<RuleDescriptor.GoalProperty> expected = Set.of(
				RuleDescriptor.GoalProperty.INVOCATION_CARDINALITY);

		assertEquals(expected, new UncontractedRule().descriptor().goalPropertiesRead());
		assertEquals(expected, new StandardCascadesRules.MinusAlternativeRule((difference, goal) -> true)
				.descriptor()
				.goalPropertiesRead());
	}

	@Test
	void exactModeRejectsRuleWithoutConvergenceContract() {
		CascadesPlanner planner = plannerWithUncontractedRule();

		IllegalArgumentException error = assertThrows(IllegalArgumentException.class,
				() -> planner.optimize(pattern(), OptimizationGoal.root()));

		assertEquals("Exact Cascades optimization requires a convergence contract: uncontracted-rule",
				error.getMessage());
	}

	@Test
	void unboundedShadowRejectsRuleWithoutConvergenceContract() {
		CascadesPlanner planner = plannerWithUncontractedRule();
		OptimizationGoal exact = OptimizationGoal.root();
		OptimizationGoal shadow = new OptimizationGoal(exact.requiredProperties(), exact.semanticScope(),
				exact.costPolicy(), exact.costBound(), exact.excludedProperties(), OptimizationGoal.SearchMode.SHADOW,
				Long.MAX_VALUE, Integer.MAX_VALUE, exact.rowGoal(), exact.estimationTier());

		IllegalArgumentException error = assertThrows(IllegalArgumentException.class,
				() -> planner.optimize(pattern(), shadow));

		assertEquals("Exact Cascades optimization requires a convergence contract: uncontracted-rule",
				error.getMessage());
	}

	@Test
	void budgetedModeMayRunUncontractedRuleToQuiescence() {
		CascadesPlan plan = plannerWithUncontractedRule()
				.optimize(pattern(), OptimizationGoal.root().asBudgeted(Duration.ofSeconds(10), 1_000));

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness());
		assertEquals(List.of(), plan.pendingTasks());
	}

	private static CascadesPlanner plannerWithUncontractedRule() {
		RuleRegistry registry = RuleRegistry.builder()
				.add(new UncontractedRule())
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		return new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				CascadesTelemetry.NO_OP);
	}

	private static StatementPattern pattern() {
		return new StatementPattern(Var.of("s"), Var.of("p"), Var.of("o"));
	}

	private static final class UncontractedRule implements CascadesRule {

		@Override
		public String id() {
			return "uncontracted-rule";
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return false;
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 0;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			return List.of();
		}
	}
}
